  it("should return empty array for empty input", () => {
    expect(nextGeneration([])).toEqual([]);
  });
  it("should kill a single live cell with no neighbors (underpopulation)", () => {
    const cells: Cell[] = [{ x: 0, y: 0 }];
    expect(nextGeneration(cells)).toEqual([]);
  });

